import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Eye, Save, Printer, MoreVertical, Copy, FileDown, Trash2, History, Plus, X, Search } from 'lucide-react';
import { getOrden, createOrden, updateOrden, deleteOrden, getClientes, getPiletas } from '../../services/api';
import { formatCurrency, badgeClass, materialesOrden, espesores, acabados, conceptosFabricacion } from '../../utils/formatters';
import CroquisEditor from './CroquisEditor';
import FirmaCanvas from './FirmaCanvas';
import Loading from '../common/Loading';
import ConfirmDialog from '../common/ConfirmDialog';

export default function OrdenForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEdit = !!id;
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);
  const [clientes, setClientes] = useState([]);
  const [piletas, setPiletas] = useState([]);
  const [menuOpen, setMenuOpen] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState(false);
  const menuRef = useRef(null);
  const clienteInputRef = useRef(null);
  const clienteDropdownRef = useRef(null);
  const [clienteSearch, setClienteSearch] = useState('');
  const [clienteFocus, setClienteFocus] = useState(false);

  const [form, setForm] = useState({
    cliente_id: '', estado: 'Presupuestado', fecha: new Date().toISOString().slice(0, 10),
    domicilio: '', email: '',
    material: '', color_tipo: '', espesor: '20 mm', acabado: 'Pulido',
    bacha: '', anafe: '',
    croquis: [],
    observaciones_diseno: '',
    detalles_fabricacion: [{ concepto: 'CORTE', detalle: '' }],
    pileta_modelo: '', pileta_imagen: '',
    subtotal: 0, traslado: 0, instalacion: 0, descuento: 0, total: 0,
    sena_recibida: 0, saldo_pendiente: 0, forma_pago: '',
    fecha_entrega: '',
    firma_cliente: null, fecha_aprobacion: '',
    observaciones: '', observaciones_importantes: '',
  });

  useEffect(() => {
    Promise.all([getClientes(), getPiletas()]).then(([clientesRes, piletaRes]) => {
      setClientes(clientesRes.data);
      setPiletas(piletaRes.data);
    });
    if (id) {
      getOrden(id).then((res) => {
        const d = res.data;
        setForm({
          cliente_id: d.cliente_id || '',
          estado: d.estado || 'Presupuestado',
          fecha: d.fecha ? d.fecha.slice(0, 10) : new Date().toISOString().slice(0, 10),
          domicilio: d.domicilio || '',
          email: d.email || '',
          material: d.material || '',
          color_tipo: d.color_tipo || '',
          espesor: d.espesor || '20 mm',
          acabado: d.acabado || 'Pulido',
          bacha: d.bacha || '',
          anafe: d.anafe || '',
          croquis: d.croquis || [],
          observaciones_diseno: d.observaciones_diseno || '',
          detalles_fabricacion: d.detalles_fabricacion?.length ? d.detalles_fabricacion : [{ concepto: 'CORTE', detalle: '' }],
          pileta_modelo: d.pileta_modelo || '',
          pileta_imagen: d.pileta_imagen || '',
          subtotal: d.subtotal || 0,
          traslado: d.traslado || 0,
          instalacion: d.instalacion || 0,
          descuento: d.descuento || 0,
          total: d.total || 0,
          sena_recibida: d.sena_recibida || 0,
          saldo_pendiente: d.saldo_pendiente || 0,
          forma_pago: d.forma_pago || '',
          fecha_entrega: d.fecha_entrega ? d.fecha_entrega.slice(0, 10) : '',
          firma_cliente: d.firma_cliente || null,
          fecha_aprobacion: d.fecha_aprobacion ? d.fecha_aprobacion.slice(0, 10) : '',
          observaciones: d.observaciones || '',
          observaciones_importantes: d.observaciones_importantes || '',
        });
        if (d.cliente_nombre) setClienteSearch(d.cliente_nombre);
        setLoading(false);
      });
    }
  }, [id]);

  useEffect(() => {
    const st = Number(form.subtotal) || 0;
    const tr = Number(form.traslado) || 0;
    const total = Math.max(0, st + tr);
    const saldo = Math.max(0, total - (Number(form.sena_recibida) || 0));
    setForm((prev) => ({ ...prev, total, saldo_pendiente: saldo }));
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [form.subtotal, form.traslado, form.sena_recibida]);

  useEffect(() => {
    const handleClick = (e) => {
      if (menuRef.current && !menuRef.current.contains(e.target)) setMenuOpen(false);
      if (clienteDropdownRef.current && !clienteDropdownRef.current.contains(e.target) &&
          clienteInputRef.current && !clienteInputRef.current.contains(e.target)) setClienteFocus(false);
    };
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  const update = (field, value) => setForm((prev) => ({ ...prev, [field]: value }));

  const clientesFiltrados = clientes.filter((c) =>
    c.nombre.toLowerCase().includes(clienteSearch.toLowerCase())
  );

  const handleSelectCliente = (c) => {
    setClienteSearch(c.nombre);
    setClienteFocus(false);
    setForm((prev) => ({
      ...prev,
      cliente_id: c.id,
      domicilio: c.direccion || prev.domicilio,
      email: c.email || prev.email,
    }));
  };

  const handleDetalleChange = (idx, field, value) => {
    const list = [...form.detalles_fabricacion];
    list[idx] = { ...list[idx], [field]: value };
    if (field === 'concepto' && value !== 'OTRA') {
      list[idx].concepto_personalizado = '';
    }
    update('detalles_fabricacion', list);
  };

  const addDetalle = () => {
    update('detalles_fabricacion', [...form.detalles_fabricacion, { concepto: 'CORTE', detalle: '' }]);
  };

  const removeDetalle = (idx) => {
    if (form.detalles_fabricacion.length <= 1) return;
    update('detalles_fabricacion', form.detalles_fabricacion.filter((_, i) => i !== idx));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = {
        ...form,
        cliente_id: Number(form.cliente_id),
        fecha: form.fecha ? new Date(form.fecha).toISOString() : null,
        subtotal: Number(form.subtotal),
        traslado: Number(form.traslado),
        total: Number(form.total),
        sena_recibida: Number(form.sena_recibida),
        saldo_pendiente: Number(form.saldo_pendiente),
        fecha_entrega: form.fecha_entrega ? new Date(form.fecha_entrega).toISOString() : null,
        fecha_aprobacion: form.fecha_aprobacion ? new Date(form.fecha_aprobacion).toISOString() : null,
      };
      if (isEdit) {
        await updateOrden(id, payload);
      } else {
        await createOrden(payload);
      }
      navigate('/ordenes');
    } catch (err) {
      alert('Error al guardar');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    await deleteOrden(id);
    navigate('/ordenes');
  };

  const handlePrint = () => window.print();

  if (loading) return <Loading />;

  return (
    <div className="orden-form">
      {/* ===== HEADER ===== */}
      <div className="orden-header">
        <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
          <div>
            <span style={{ fontSize: 22, fontWeight: 700 }}>Orden N° {form.numero || (isEdit ? '' : 'A-_____')}</span>
          </div>
          <span className={badgeClass(form.estado)} style={{ fontSize: 13, padding: '4px 14px' }}>{form.estado}</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <button className="btn btn-outline" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <Eye size={16} /> VISTA PREVIA PDF
          </button>
          <button className="btn btn-primary" onClick={handleSubmit} disabled={saving} style={{ background: '#b91c1c', display: 'flex', alignItems: 'center', gap: 6, padding: '8px 20px' }}>
            <Save size={16} /> {saving ? 'GUARDANDO...' : 'GUARDAR'}
          </button>
          <button className="btn btn-outline" onClick={handlePrint} style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <Printer size={16} /> IMPRIMIR
          </button>
          <div ref={menuRef} style={{ position: 'relative' }}>
            <button className="btn btn-outline" onClick={() => setMenuOpen(!menuOpen)} style={{ padding: '8px 10px' }}>
              <MoreVertical size={18} />
            </button>
            {menuOpen && (
              <div className="dropdown-menu">
                <div className="dropdown-item" onClick={() => { setMenuOpen(false); alert('Duplicar orden'); }}>
                  <Copy size={16} /> Duplicar
                </div>
                <div className="dropdown-item" onClick={() => { setMenuOpen(false); alert('Exportar PDF'); }}>
                  <FileDown size={16} /> Exportar PDF
                </div>
                <div className="dropdown-item" style={{ color: '#ef4444' }} onClick={() => { setMenuOpen(false); setDeleteConfirm(true); }}>
                  <Trash2 size={16} /> Eliminar
                </div>
                <div className="dropdown-item" onClick={() => { setMenuOpen(false); alert('Historial de cambios'); }}>
                  <History size={16} /> Historial
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      <form onSubmit={handleSubmit}>
        {/* ===== DATOS DEL CLIENTE ===== */}
        <div className="card" style={{ marginTop: 16 }}>
          <div className="orden-grid-4">
            <div className="form-group">
              <label>Fecha</label>
              <input type="date" className="input" value={form.fecha} onChange={(e) => update('fecha', e.target.value)} />
            </div>
            <div className="form-group" style={{ position: 'relative' }}>
              <label>Cliente *</label>
              <input
                ref={clienteInputRef}
                className="input"
                required
                placeholder="Buscar cliente..."
                value={clienteSearch}
                onChange={(e) => { setClienteSearch(e.target.value); setClienteFocus(true); }}
                onFocus={() => setClienteFocus(true)}
                style={{ paddingLeft: 36 }}
              />
              <Search size={16} style={{ position: 'absolute', left: 12, top: 38, color: '#94a3b8' }} />
              {clienteFocus && clientesFiltrados.length > 0 && (
                <div
                  ref={clienteDropdownRef}
                  style={{
                    position: 'absolute', top: '100%', left: 0, right: 0, zIndex: 50,
                    background: '#fff', border: '1px solid #e5e7eb', borderRadius: 8,
                    boxShadow: '0 10px 25px rgba(0,0,0,0.1)', maxHeight: 200, overflowY: 'auto',
                  }}
                >
                  {clientesFiltrados.map((c) => (
                    <div
                      key={c.id}
                      onClick={() => handleSelectCliente(c)}
                      style={{
                        padding: '10px 14px', cursor: 'pointer', fontSize: 14,
                        borderBottom: '1px solid #f3f4f6',
                      }}
                      onMouseEnter={(e) => e.target.style.background = '#f3f4f6'}
                      onMouseLeave={(e) => e.target.style.background = 'transparent'}
                    >
                      <div style={{ fontWeight: 600 }}>{c.nombre}</div>
                      {c.telefono && <div style={{ fontSize: 12, color: '#64748b' }}>{c.telefono}</div>}
                    </div>
                  ))}
                </div>
              )}
            </div>
            <div className="form-group">
              <label>Teléfono</label>
              <input className="input" value={clientes.find((c) => c.id === Number(form.cliente_id))?.telefono || ''} disabled />
            </div>
            <div className="form-group">
              <label>E-mail</label>
              <input className="input" value={form.email} onChange={(e) => update('email', e.target.value)} />
            </div>
          </div>
          <div className="form-group" style={{ marginTop: 8 }}>
            <label>Domicilio</label>
            <input className="input" value={form.domicilio} onChange={(e) => update('domicilio', e.target.value)} placeholder="Calle N° - Ciudad - Provincia" />
          </div>
        </div>

        {/* ===== ÁREA CENTRAL: Croquis 70% | Materiales 30% ===== */}
        <div style={{ display: 'flex', gap: 16, marginTop: 16 }}>
          <div style={{ flex: 7, minWidth: 0 }}>
            <CroquisEditor croquis={form.croquis} onChange={(v) => update('croquis', v)} />
          </div>
          <div style={{ flex: 3, minWidth: 0 }}>
            <div className="card" style={{ height: '100%' }}>
              <h3 className="section-title">MATERIALES</h3>
              <div className="form-group">
                <label>Material</label>
                <select className="input" value={form.material} onChange={(e) => update('material', e.target.value)}>
                  <option value="">Seleccionar...</option>
                  {materialesOrden.map((m) => <option key={m} value={m}>{m}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label>Color / Tipo</label>
                <input className="input" value={form.color_tipo} onChange={(e) => update('color_tipo', e.target.value)} placeholder="Ej: Negro Brasil" />
              </div>
              <div className="form-row" style={{ gap: 8 }}>
                <div className="form-group" style={{ flex: 1 }}>
                  <label>Espesor</label>
                  <select className="input" value={form.espesor} onChange={(e) => update('espesor', e.target.value)}>
                    {espesores.map((e) => <option key={e} value={e}>{e}</option>)}
                  </select>
                </div>
                <div className="form-group" style={{ flex: 1 }}>
                  <label>Acabado</label>
                  <select className="input" value={form.acabado} onChange={(e) => update('acabado', e.target.value)}>
                    {acabados.map((a) => <option key={a} value={a}>{a}</option>)}
                  </select>
                </div>
              </div>
              <div className="form-group">
                <label>Observaciones del diseño</label>
                <textarea className="input" rows={4} value={form.observaciones_diseno} onChange={(e) => update('observaciones_diseno', e.target.value)} placeholder="Zócalo de 7 cm. Frente de 4 cm. Incluye 3 perforaciones..." />
              </div>
            </div>
          </div>
        </div>

        {/* ===== SECCIÓN INFERIOR: 4 paneles ===== */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, marginTop: 16 }}>
          {/* Panel 1: Detalle de Fabricación */}
          <div className="card">
            <h3 className="section-title">DETALLE DE FABRICACIÓN</h3>
            <table className="table" style={{ fontSize: 13 }}>
              <thead>
                <tr>
                  <th>Concepto</th>
                  <th>Detalle</th>
                  <th style={{ width: 30 }}></th>
                </tr>
              </thead>
              <tbody>
                {form.detalles_fabricacion.map((d, i) => (
                  <tr key={i}>
                    <td>
                      <select className="input" style={{ fontSize: 12, padding: '4px 8px' }} value={d.concepto} onChange={(e) => handleDetalleChange(i, 'concepto', e.target.value)}>
                        {conceptosFabricacion.map((c) => <option key={c} value={c}>{c}</option>)}
                      </select>
                    </td>
                    <td>
                      {d.concepto === 'OTRA' ? (
                        <div style={{ display: 'flex', gap: 4 }}>
                          <input className="input" style={{ fontSize: 12, padding: '4px 8px', width: '40%' }} value={d.concepto_personalizado || ''} onChange={(e) => handleDetalleChange(i, 'concepto_personalizado', e.target.value)} placeholder="Nombre" />
                          <input className="input" style={{ fontSize: 12, padding: '4px 8px', width: '60%' }} value={d.detalle} onChange={(e) => handleDetalleChange(i, 'detalle', e.target.value)} placeholder="Detalle" />
                        </div>
                      ) : (
                        <input className="input" style={{ fontSize: 12, padding: '4px 8px' }} value={d.detalle} onChange={(e) => handleDetalleChange(i, 'detalle', e.target.value)} placeholder="Cant / ML / cm" />
                      )}
                    </td>
                    <td>
                      <button type="button" className="btn btn-outline" style={{ padding: '2px 6px' }} onClick={() => removeDetalle(i)}>
                        <X size={14} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            <button type="button" className="btn btn-outline" onClick={addDetalle} style={{ marginTop: 8, fontSize: 13, padding: '6px 14px' }}>
              <Plus size={14} /> Agregar concepto
            </button>
          </div>

          {/* Panel 2: Pileta */}
          <div className="card">
            <h3 className="section-title">PILETA</h3>
            <div className="form-group">
              <label>Seleccionar pileta</label>
              <select className="input" value={form.pileta_modelo} onChange={(e) => update('pileta_modelo', e.target.value)}>
                <option value="">Sin pileta</option>
                {piletas.map((p) => <option key={p.id} value={`${p.marca} ${p.modelo}`}>{p.marca} - {p.modelo}</option>)}
              </select>
            </div>
            {form.pileta_modelo && (
              <div style={{ marginTop: 12, padding: 12, background: '#f8fafc', borderRadius: 8, textAlign: 'center' }}>
                <div style={{ width: '100%', height: 100, background: '#e5e7eb', borderRadius: 8, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#9ca3af', fontSize: 13 }}>
                  {form.pileta_modelo}
                </div>
                <p style={{ fontSize: 12, color: '#64748b', marginTop: 6 }}>Imagen referencial de la pileta</p>
              </div>
            )}
          </div>

          {/* Panel 3: Presupuesto */}
          <div className="card">
            <h3 className="section-title">PRESUPUESTO</h3>
            <div className="form-group" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <label>Subtotal</label>
              <input type="number" className="input" style={{ width: 160, textAlign: 'right', fontWeight: 600 }} value={form.subtotal} onChange={(e) => update('subtotal', e.target.value)} />
            </div>
            <div className="form-group" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <label>SIN CARGO</label>
              <input type="number" className="input" style={{ width: 160, textAlign: 'right', color: '#22c55e', fontWeight: 600 }} value={form.traslado} onChange={(e) => update('traslado', e.target.value)} />
            </div>
            <div style={{ borderTop: '2px solid #e5e7eb', paddingTop: 12, marginTop: 8 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span style={{ fontSize: 20, fontWeight: 700 }}>TOTAL</span>
                <span style={{ fontSize: 24, fontWeight: 700, color: '#dc2626' }}>{formatCurrency(form.total)}</span>
              </div>
            </div>
            <div style={{ marginTop: 12, borderTop: '1px solid #e5e7eb', paddingTop: 12 }}>
              <div className="form-group" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <label>Seña recibida</label>
                <input type="number" className="input" style={{ width: 160, textAlign: 'right' }} value={form.sena_recibida} onChange={(e) => update('sena_recibida', e.target.value)} />
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 8 }}>
                <span style={{ fontWeight: 600 }}>Saldo pendiente</span>
                <span style={{ fontSize: 18, fontWeight: 700, color: '#1e40af' }}>{formatCurrency(form.saldo_pendiente)}</span>
              </div>
              <div className="form-group" style={{ marginTop: 8 }}>
                <label>Forma de pago</label>
                <input className="input" value={form.forma_pago} onChange={(e) => update('forma_pago', e.target.value)} placeholder="Ej: Efectivo / Transferencia" />
              </div>
            </div>
          </div>

          {/* Panel 4: Aprobación */}
          <div className="card">
            <h3 className="section-title">APROBACIÓN DEL CLIENTE</h3>
            <p style={{ fontSize: 13, color: '#475569', marginBottom: 12 }}>
              El cliente aprueba el diseño y presupuesto.
            </p>
            <FirmaCanvas
              value={form.firma_cliente}
              onChange={(v) => update('firma_cliente', v)}
              label="Firma del cliente"
              height={140}
            />
            <div className="form-group" style={{ marginTop: 8 }}>
              <label>Fecha de aprobación</label>
              <input type="date" className="input" value={form.fecha_aprobacion} onChange={(e) => update('fecha_aprobacion', e.target.value)} />
            </div>
          </div>
        </div>

        {/* ===== OBSERVACIONES IMPORTANTES ===== */}
        <div className="card" style={{ marginTop: 16, background: '#f9fafb', border: '1px solid #b91c1c' }}>
          <h3 className="section-title" style={{ color: '#b91c1c' }}>OBSERVACIONES IMPORTANTES PARA EL CLIENTE</h3>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 6, fontSize: 14, color: '#374151', marginBottom: 12 }}>
            <div>✓ No se realizan instalaciones.</div>
            <div>✓ No se realizan entregas con lluvia.</div>
            <div>✓ La descarga se realiza al pie del camión.</div>
            <div>✓ Debe haber personas para descargar.</div>
            <div>✓ El traslado lo realiza únicamente el fletero.</div>
          </div>
          <div className="form-group">
            <label style={{ fontWeight: 600 }}>Observaciones adicionales</label>
            <textarea className="input" rows={3} value={form.observaciones_importantes} onChange={(e) => update('observaciones_importantes', e.target.value)} placeholder="Agregar observaciones adicionales..." />
          </div>
        </div>

        {/* ===== BOTONES FINALES ===== */}
        <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end', marginTop: 16 }}>
          <button type="button" className="btn btn-outline" onClick={() => navigate('/ordenes')}>Cancelar</button>
          <button type="submit" className="btn btn-primary" disabled={saving} style={{ background: '#b91c1c' }}>
            <Save size={16} /> {saving ? 'GUARDANDO...' : 'GUARDAR'}
          </button>
        </div>
      </form>

      <ConfirmDialog isOpen={deleteConfirm} onClose={() => setDeleteConfirm(false)} onConfirm={handleDelete} title="Eliminar orden" message="¿Estás seguro de eliminar esta orden de trabajo?" />
    </div>
  );
}
